    vec2 d0 = z - root0;
    vec2 d1 = z - root1;
    vec2 d2 = z - root2;
    if (dot(d0, d0) < convergeDist) { it = j; rootId = 0; break; }
    if (dot(d1, d1) < convergeDist) { it = j; rootId = 1; break; }
    if (dot(d2, d2) < convergeDist) { it = j; rootId = 2; break; }

    if (dot(z, z) > bailoutSq) { it = j; break; }
    it = j + 1;
