    float t = fract(smoothVal / 64.0 + uTime * 0.0001);
    int pal = schemeInt < 50 ? schemeInt : (schemeInt - 50) - ((schemeInt - 50) / 4) * 4;
    vec3 baseCol = palette(t, pal);
    // Tint by root
