  int it = 0;

  for (int j = 0; j < MAX_ITERS; j++) {
    if (j >= target) { it = target; break; }
    vec2 z2 = cmul(z, z);
    vec2 z3 = cmul(z2, z);
    // f(z) = z³−1, f'(z) = 3z²
    // Newton step: (z³−1)/(3z²) = (z - 1/z²)/3
    // z_next = z − (z³−1)/(3z²) + c = (2z³+1)/(3z²) + c
