    // So: der = (1 - (z³+2)/(3z³))·der + 1 = ((2z³-2)/(3z³))·der + 1
    vec2 dF = cdiv(2.0*(z3 - vec2(1.0,0.0)), 3.0*z3);
    der = cmul(dF, der) + vec2(1.0, 0.0);
    z = z - newton_step + c;
