  int schemeInt = int(uColorScheme);
  vec2 z   = uv / max(0.000001, uZoom) + uCenter;  // pixel = z₀
  vec2 c   = vec2(0.0, 0.50);  // fixed Nova Julia parameter
  vec2 der = vec2(1.0, 0.0);   // dz/dz₀ = 1 initially

  float bailoutSq = uBailout * uBailout;
  const int MAX_ITERS = 500;
  int target = int(clamp(uIterations, 0.0, float(MAX_ITERS)));
  int it = 0;

  for (int j = 0; j < MAX_ITERS; j++) {
    if (j >= target) { it = target; break; }
    vec2 z2  = cmul(z, z);
    vec2 z3  = cmul(z2, z);
    vec2 z4  = cmul(z2, z2);
    // Pole guard
    if (dot(z3, z3) < 1e-12) { it = j; break; }
    // N'(z) = 3(z⁴−1)/(4z⁴) — derivative of Newton step
    vec2 z4m1   = z4 - vec2(1.0, 0.0);
